use sqlx::PgPool;

use crate::domain::{Password, User, ValidatedEmail};
use crate::infrastructure::UserRepository;

#[derive(Debug, thiserror::Error)]
pub enum RegistrationError {
    #[error("{0}")]
    InvalidEmail(#[from] crate::domain::email::EmailValidationError),
    #[error("{0}")]
    InvalidPassword(#[from] crate::domain::password::PasswordError),
    #[error("An account with this email already exists")]
    DuplicateEmail,
    #[error(transparent)]
    Unexpected(#[from] anyhow::Error),
}

#[tracing::instrument(name = "Registering a new user", skip(pool, password))]
pub async fn register_user(
    pool: &PgPool,
    email: String,
    password: &str,
) -> Result<User, RegistrationError> {
    let validated_email = ValidatedEmail::parse(email)?;
    let hashed_password = Password::parse(password)?;

    // Check for duplicate email
    let existing = UserRepository::find_by_email(pool, validated_email.as_str())
        .await
        .map_err(|e| RegistrationError::Unexpected(anyhow::anyhow!(e)))?;

    if existing.is_some() {
        return Err(RegistrationError::DuplicateEmail);
    }

    let user = User::new(validated_email, hashed_password);

    UserRepository::insert(pool, &user)
        .await
        .map_err(|e| RegistrationError::Unexpected(anyhow::anyhow!(e)))?;

    tracing::info!(
        user_id = %user.id,
        "New user registered"
    );

    Ok(user)
}

