use askama::Template;
use axum::extract::State;
use axum::http::StatusCode;
use axum::response::{Html, IntoResponse, Redirect, Response};
use axum::Form;
use sqlx::PgPool;

use crate::services::{register_user, RegistrationError};

#[derive(Template)]
#[template(path = "register.html")]
struct RegisterTemplate {
    email_value: String,
    email_error: Option<String>,
    password_error: Option<String>,
    password_confirm_error: Option<String>,
    general_error: Option<String>,
}

pub async fn register_form() -> impl IntoResponse {
    let template = RegisterTemplate {
        email_value: String::new(),
        email_error: None,
        password_error: None,
        password_confirm_error: None,
        general_error: None,
    };
    Html(template.render().unwrap())
}

#[derive(serde::Deserialize)]
pub struct RegisterFormData {
    email: String,
    password: String,
    password_confirm: String,
}

pub async fn register_submit(
    State(pool): State<PgPool>,
    Form(form): Form<RegisterFormData>,
) -> Response {
    // Validate password confirmation before calling the service
    if form.password != form.password_confirm {
        let template = RegisterTemplate {
            email_value: form.email,
            email_error: None,
            password_error: None,
            password_confirm_error: Some("Passwords do not match".to_string()),
            general_error: None,
        };
        return (
            StatusCode::UNPROCESSABLE_ENTITY,
            Html(template.render().unwrap()),
        )
            .into_response();
    }

    match register_user(&pool, form.email.clone(), &form.password).await {
        Ok(_user) => Redirect::to("/login").into_response(),
        Err(e) => {
            let (email_error, password_error, general_error) = match &e {
                RegistrationError::InvalidEmail(err) => (Some(err.to_string()), None, None),
                RegistrationError::InvalidPassword(err) => (None, Some(err.to_string()), None),
                // Security: do not reveal whether the email exists in the system
                RegistrationError::DuplicateEmail => (
                    None,
                    None,
                    Some(
                        "Unable to create account. Please check your details and try again."
                            .to_string(),
                    ),
                ),
                RegistrationError::Unexpected(_) => {
                    tracing::error!(error = %e, "Unexpected error during registration");
                    (
                        None,
                        None,
                        Some("Something went wrong. Please try again.".to_string()),
                    )
                }
            };

            let template = RegisterTemplate {
                email_value: form.email,
                email_error,
                password_error,
                password_confirm_error: None,
                general_error,
            };

            (
                StatusCode::UNPROCESSABLE_ENTITY,
                Html(template.render().unwrap()),
            )
                .into_response()
        }
    }
}

