use crate::helpers::spawn_app;

#[tokio::test]
async fn register_returns_200_for_get_request() {
    let app = spawn_app().await;

    let client = reqwest::Client::new();
    let response = client
        .get(format!("{}/register", &app.address))
        .send()
        .await
        .expect("Failed to execute request");

    assert_eq!(response.status().as_u16(), 200);
}

#[tokio::test]
async fn register_returns_200_with_form_html() {
    let app = spawn_app().await;

    let client = reqwest::Client::new();
    let response = client
        .get(format!("{}/register", &app.address))
        .send()
        .await
        .expect("Failed to execute request");

    let body = response.text().await.unwrap();
    assert!(body.contains("<form"));
    assert!(body.contains(r#"action="/register""#));
    assert!(body.contains(r#"<label for="email">"#));
    assert!(body.contains(r#"<label for="password">"#));
    assert!(body.contains(r#"<label for="password-confirm">"#));
    assert!(body.contains("Must be at least 8 characters"));
}

#[tokio::test]
async fn register_creates_user_and_redirects_on_valid_input() {
    let app = spawn_app().await;

    let client = reqwest::Client::builder()
        .redirect(reqwest::redirect::Policy::none())
        .build()
        .unwrap();

    let response = client
        .post(format!("{}/register", &app.address))
        .header("Content-Type", "application/x-www-form-urlencoded")
        .body("email=test%40example.com&password=securepassword123&password_confirm=securepassword123")
        .send()
        .await
        .expect("Failed to execute request");

    assert_eq!(response.status().as_u16(), 303);

    let row = sqlx::query!("SELECT email FROM users WHERE email = 'test@example.com'")
        .fetch_one(&app.pool)
        .await
        .expect("Failed to find user in database");

    assert_eq!(row.email, "test@example.com");
}

#[tokio::test]
async fn register_returns_422_when_email_is_empty() {
    let app = spawn_app().await;

    let client = reqwest::Client::builder()
        .redirect(reqwest::redirect::Policy::none())
        .build()
        .unwrap();

    let response = client
        .post(format!("{}/register", &app.address))
        .header("Content-Type", "application/x-www-form-urlencoded")
        .body("email=&password=securepassword123&password_confirm=securepassword123")
        .send()
        .await
        .expect("Failed to execute request");

    assert_eq!(response.status().as_u16(), 422);
    let body = response.text().await.unwrap();
    assert!(body.contains("Email cannot be empty"));
}

#[tokio::test]
async fn register_returns_422_when_email_is_invalid() {
    let app = spawn_app().await;

    let client = reqwest::Client::builder()
        .redirect(reqwest::redirect::Policy::none())
        .build()
        .unwrap();

    let response = client
        .post(format!("{}/register", &app.address))
        .header("Content-Type", "application/x-www-form-urlencoded")
        .body("email=notanemail&password=securepassword123&password_confirm=securepassword123")
        .send()
        .await
        .expect("Failed to execute request");

    assert_eq!(response.status().as_u16(), 422);
    let body = response.text().await.unwrap();
    assert!(body.contains("@"));
}

#[tokio::test]
async fn register_returns_422_when_password_is_too_short() {
    let app = spawn_app().await;

    let client = reqwest::Client::builder()
