#[tokio::test]
async fn register_returns_422_when_password_is_empty() {
    let app = spawn_app().await;

    let client = reqwest::Client::builder()
        .redirect(reqwest::redirect::Policy::none())
        .build()
        .unwrap();

    let response = client
        .post(format!("{}/register", &app.address))
        .header("Content-Type", "application/x-www-form-urlencoded")
        .body("email=test%40example.com&password=&password_confirm=")
        .send()
        .await
        .expect("Failed to execute request");

    assert_eq!(response.status().as_u16(), 422);
    let body = response.text().await.unwrap();
    assert!(body.contains("Password cannot be empty"));
}

#[tokio::test]
async fn register_returns_422_when_passwords_do_not_match() {
    let app = spawn_app().await;

    let client = reqwest::Client::builder()
        .redirect(reqwest::redirect::Policy::none())
        .build()
        .unwrap();

    let response = client
        .post(format!("{}/register", &app.address))
        .header("Content-Type", "application/x-www-form-urlencoded")
        .body("email=test%40example.com&password=securepassword123&password_confirm=differentpassword")
        .send()
        .await
        .expect("Failed to execute request");

    assert_eq!(response.status().as_u16(), 422);
    let body = response.text().await.unwrap();
    assert!(body.contains("Passwords do not match"));
}

#[tokio::test]
async fn register_returns_generic_error_for_duplicate_email() {
    let app = spawn_app().await;

    let client = reqwest::Client::builder()
        .redirect(reqwest::redirect::Policy::none())
        .build()
        .unwrap();

    // Register first user
    client
        .post(format!("{}/register", &app.address))
        .header("Content-Type", "application/x-www-form-urlencoded")
        .body("email=dupe%40example.com&password=securepassword123&password_confirm=securepassword123")
        .send()
        .await
        .expect("Failed to execute request");

    // Attempt duplicate registration
    let response = client
        .post(format!("{}/register", &app.address))
        .header("Content-Type", "application/x-www-form-urlencoded")
        .body("email=dupe%40example.com&password=securepassword123&password_confirm=securepassword123")
        .send()
        .await
        .expect("Failed to execute request");

    assert_eq!(response.status().as_u16(), 422);
    let body = response.text().await.unwrap();
    // Security: error message should NOT reveal that the email already exists
    assert!(!body.contains("already exists"));
    assert!(body.contains("Unable to create account"));
}

#[tokio::test]
async fn register_returns_422_when_form_data_is_missing() {
    let app = spawn_app().await;

    let client = reqwest::Client::builder()
        .redirect(reqwest::redirect::Policy::none())
        .build()
        .unwrap();

    let response = client
        .post(format!("{}/register", &app.address))
        .header("Content-Type", "application/x-www-form-urlencoded")
        .body("")
        .send()
        .await
        .expect("Failed to execute request");

    assert_eq!(response.status().as_u16(), 422);
}

#[tokio::test]
async fn register_preserves_email_on_validation_error() {
    let app = spawn_app().await;

    let client = reqwest::Client::builder()
        .redirect(reqwest::redirect::Policy::none())
        .build()
        .unwrap();

    let response = client
        .post(format!("{}/register", &app.address))
        .header("Content-Type", "application/x-www-form-urlencoded")
        .body("email=test%40example.com&password=short&password_confirm=short")
        .send()
        .await
        .expect("Failed to execute request");

    let body = response.text().await.unwrap();
    // The email should be preserved in the form so the user doesn't have to re-type it
    assert!(body.contains("test@example.com"));
}

