use askama::Template;
use axum::extract::State;
use axum::http::StatusCode;
use axum::response::{Html, IntoResponse, Redirect, Response};
use axum::Form;
use sqlx::PgPool;
use tower_sessions::Session;

use crate::services::{authenticate_user, AuthenticationError};

pub const USER_ID_SESSION_KEY: &str = "user_id";

#[derive(Template)]
#[template(path = "login.html")]
struct LoginTemplate {
    email_value: String,
    error_message: Option<String>,
}

pub async fn login_form() -> impl IntoResponse {
    let template = LoginTemplate {
        email_value: String::new(),
        error_message: None,
    };
    Html(template.render().unwrap())
}

#[derive(serde::Deserialize)]
pub struct LoginFormData {
    email: String,
    password: String,
}

pub async fn login_submit(
    State(pool): State<PgPool>,
    session: Session,
    Form(form): Form<LoginFormData>,
) -> Response {
    match authenticate_user(&pool, &form.email, &form.password).await {
        Ok(user) => {
            session.cycle_id().await.unwrap();
            session
                .insert(USER_ID_SESSION_KEY, user.id.as_uuid().to_string())
                .await
                .unwrap();
            Redirect::to("/todos").into_response()
        }
        Err(e) => {
            let error_message = match &e {
                AuthenticationError::InvalidCredentials => {
                    tracing::warn!(email = %form.email, "Failed login attempt");
                    "Invalid email or password".to_string()
                }
                AuthenticationError::Unexpected(_) => {
                    tracing::error!(error = %e, "Unexpected error during authentication");
                    "Something went wrong. Please try again.".to_string()
                }
            };

            let template = LoginTemplate {
                email_value: form.email,
                error_message: Some(error_message),
            };

            (StatusCode::UNAUTHORIZED, Html(template.render().unwrap())).into_response()
        }
    }
}

pub async fn logout(session: Session) -> Redirect {
    session.flush().await.unwrap();
    Redirect::to("/login")
}

